export type IconType = keyof typeof ICON_SYSTEM;

interface IconsProps {
  name: IconType;
  className?: string;
}

export function Icons({ name, className = 'w-6 h-6' }: IconsProps) {
  const iconElement = ICON_SYSTEM[name];

  return React.cloneElement(iconElement, {
    className: className,
    'aria-hidden': 'true',
  });
}
